 * saveUserPreference(preferenceName, preferenceValue)
 *   @param {string} preferenceName  - "columns" | "orderBy" | "orderDirection" | "limit".
 *   @param {string} preferenceValue - Serialized value to persist.
 *   @return {void}
 *
 * showAppliedFilters()
 *   @return {boolean} Whether the applied filters summary bar is visible.
 *
 * showTableMetadata()
 *   @return {boolean} Whether the metadata bar (record count, pagination info) is visible.
 *
 * ─────────────────────────────────────────────────────────────────────────────
 * SERVER ACTIONS USED BY CLIENT
 * ─────────────────────────────────────────────────────────────────────────────
 * getChoiceValues            -> data.choiceValues
 * getReferenceDisplayValue   -> data.displayValue
 * getTableColumns            -> data.columns
 * getTableData               -> data.records + data.orderBy + data.orderDirection
 * getTotalRecords            -> data.totalRecords
 * getAppliedFiltersInfoMessage -> data.appliedFiltersHtml
 * ─────────────────────────────────────────────────────────────────────────────
 */
(function () {
    const transactionId = input?.transactionId || gs.generateGUID();
    const tableProviderScriptInclude =
        input?.tableProviderScriptInclude ||
        options?.tableProviderScriptInclude;

    const logger = new Logger({
        transactionId: transactionId,
        source: "scm-table.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });

    if (!tableProviderScriptInclude) {
        data.redirectTo404 = true;
        logger.error("Table provider Script Include is missing");
        return;
    }

    data.transactionId = transactionId;
    data.tableProviderScriptInclude = tableProviderScriptInclude;

    let widgetHelper;
    try {
        const ProviderClass = x_680259_scm[tableProviderScriptInclude];

        widgetHelper = new ProviderClass({
            transactionId: transactionId,
            providerParams: input?.providerParams || options?.providerParams,
        });
    } catch (error) {
        data.redirectTo404 = true;
        logger.error({
            message: "Error initializing provider",
            error: error.message,
            tableProviderScriptInclude: tableProviderScriptInclude,
        });
        return;
    }

    if (!validateProviderContract(widgetHelper, logger)) {
        data.redirectTo404 = true;
        return;
    }

    if (input && input.action === "savePreference") {
        if (!widgetHelper.canSavePreferences()) return;

        widgetHelper.saveUserPreference(
            input.preferenceName,
            input.preferenceValue,
        );
        return;
    }

    if (input && input.action === "getAppliedFiltersInfoMessage") {
        const filtersForMessage = resolveEffectiveFilters(input.appliedFilters);

        data.appliedFiltersHtml =
            widgetHelper.getAppliedFiltersInfoMessage(filtersForMessage);
        return;
    }

    if (input && input.action === "getTotalRecords") {
        const effectiveFiltersForCount = resolveEffectiveFilters(input.filters);

        data.totalRecords = widgetHelper.getTotalRecords(
            effectiveFiltersForCount,
        );
        return;
    }

    if (input && input.action === "getChoiceValues") {
        data.choiceValues = widgetHelper.getChoiceValues(input.fieldName);
        return;
    }

    if (input && input.action === "getReferenceDisplayValue") {
        data.displayValue = getReferenceDisplayValue(input.table, input.sysId);
        return;
    }

    if (input && input.action === "getTableColumns") {
        data.columns = normalizeColumns(widgetHelper.getTableColumns());
        return;
    }

    if (input && input.action === "revertListViewToDefault") {
        widgetHelper.saveUserPreference(
            "columns",
            JSON.stringify(widgetHelper.getDefaultColumns()),
        );
        data.columns = normalizeColumns(widgetHelper.getDefaultColumns());
        return;
    }

    if (input && input.action === "getTableData") {
        const columns = normalizeColumns(widgetHelper.getTableColumns());
        const effectiveFilters = resolveEffectiveFilters(input.filters);

        if (typeof widgetHelper.getCellContent !== "function") {
            logger.error(
                "Provider must implement getCellContent(field, record)",
            );
            data.records = [];
            data.orderDirection = widgetHelper.getOrderDirection();
            data.orderBy = widgetHelper.getOrderBy();
            return;
        }

        const providerRecords = widgetHelper.getTableData({
            filters: effectiveFilters,
            page: input.page,
        });

        if (!Array.isArray(providerRecords)) {
            logger.error({
                message: "Provider getTableData must return an array",
                provider: tableProviderScriptInclude,
                returnedType: typeof providerRecords,
