    data.title = widgetHelper.getPageTitle();

    data.showNewRecordButton = widgetHelper.canCreate();

    data.detailViewPage = widgetHelper.getDetailViewPage();
    data.idField = widgetHelper.getIdField();

    data.canFilter = widgetHelper.canFilter();
    data.filterFields = buildUnifiedFilterFields(
        widgetHelper.getAllAvailableColumns(),
        widgetHelper.getFilterFields(),
    );

    if (data.canFilter && data.filterFields.length === 0) {
        data.canFilter = false;
    }

    data.limit = widgetHelper.getTableLimit();

    data.canSavePreferences = widgetHelper.canSavePreferences();

    data.allColumnsAvailable = widgetHelper.getAllAvailableColumns();
    data.columns = normalizeColumns(widgetHelper.getTableColumns());

    data.canConfigureColumns = widgetHelper.canConfigureColumns();
    data.showMetadata = widgetHelper.showTableMetadata();
    data.showAppliedFilters = widgetHelper.showAppliedFilters();
    data.rowClickAction =
        typeof widgetHelper.getRowClickAction === "function"
            ? widgetHelper.getRowClickAction()
