function decorateRecords(widgetHelper, records, columns) {
    var hasContextMenu = typeof widgetHelper.getContextMenuItems === "function";
    var rowClickAction =
        typeof widgetHelper.getRowClickAction === "function"
            ? widgetHelper.getRowClickAction()
            : {};
    var clickAction = rowClickAction.action || {};

    return (records || []).map(function (record) {
        var decoratedRecord = Object.assign({}, record);
        decoratedRecord.__cellContent = {};

        for (var i = 0; i < columns.length; i++) {
            var field = columns[i];
            decoratedRecord.__cellContent[field.name] = normalizeCellContent(
                widgetHelper.getCellContent(field, record),
            );
        }

        if (hasContextMenu) {
            decoratedRecord.__contextMenuItems = normalizeContextMenuItems(
                widgetHelper.getContextMenuItems(record),
            );
        }

        // Ensure custom providers returning plain objects preserve link fields.
        if (clickAction.type === "link" && clickAction.urlField) {
            var urlField = clickAction.urlField;
            if (
                !decoratedRecord.hasOwnProperty(urlField) &&
                record.hasOwnProperty(urlField)
            ) {
                decoratedRecord[urlField] = record[urlField];
            }
        }

        return decoratedRecord;
    });
}

function normalizeCellContent(cellContent) {
    var normalizedLayout = "stack";

    if (!cellContent) {
        return {
            layout: normalizedLayout,
            blocks: [],
        };
    }

    if (Array.isArray(cellContent)) {
        return {
            layout: normalizedLayout,
            blocks: cellContent.map(normalizeCellBlock).filter(Boolean),
        };
    }

    if (cellContent.blocks && Array.isArray(cellContent.blocks)) {
        if (cellContent.layout === "inline" || cellContent.layout === "stack") {
            normalizedLayout = cellContent.layout;
        }

        return {
            layout: normalizedLayout,
            blocks: cellContent.blocks.map(normalizeCellBlock).filter(Boolean),
        };
    }

    return {
        layout: normalizedLayout,
        blocks: [normalizeCellBlock(cellContent)].filter(Boolean),
    };
}

function normalizeCellBlock(block) {
    if (block == null) {
        return null;
    }

    if (typeof block === "string" || typeof block === "number") {
        return { value: String(block) };
    }

    if (typeof block !== "object") {
        return null;
    }

    var normalized = {
        value: String(block.value || ""),
    };

    if (typeof block.className === "string" && block.className) {
        normalized.className = block.className;
    }

    if (typeof block.href === "string" && block.href) {
        var safeBlockHref = sanitizeHref(block.href);
        if (safeBlockHref) {
            normalized.href = safeBlockHref;
        }
    }

    return normalized;
}

function normalizeContextMenuItems(items) {
    if (!Array.isArray(items)) {
        return [];
    }

    return items.map(normalizeContextMenuItem).filter(Boolean);
}

function normalizeContextMenuItem(item) {
    if (!item || typeof item !== "object") {
        return null;
    }

    if (typeof item.label !== "string" || !item.label.trim()) {
        return null;
    }

    if (!item.action || typeof item.action !== "object") {
        return null;
    }

    var normalizedAction = {};

    if (typeof item.action.clipboard === "string") {
        normalizedAction.clipboard = item.action.clipboard;
    }

    if (typeof item.action.href === "string" && item.action.href) {
        var safeActionHref = sanitizeHref(item.action.href);
        if (safeActionHref) {
            normalizedAction.href = safeActionHref;
        }

        if (
            normalizedAction.href &&
            typeof item.action.target === "string" &&
            item.action.target
        ) {
            normalizedAction.target = sanitizeTarget(item.action.target);
        }
    }

    if (
        item.action.broadcast &&
        typeof item.action.broadcast === "object" &&
        typeof item.action.broadcast.eventName === "string" &&
        item.action.broadcast.eventName
    ) {
        normalizedAction.broadcast = {
            eventName: item.action.broadcast.eventName,
            payload: item.action.broadcast.payload || {},
        };
    }

    if (Object.keys(normalizedAction).length === 0) {
        return null;
    }

    var normalizedItem = {
        label: item.label,
        action: normalizedAction,
    };

    if (typeof item.iconClass === "string" && item.iconClass) {
        normalizedItem.iconClass = item.iconClass;
    }

    if (typeof item.iconName === "string" && item.iconName) {
        normalizedItem.iconName = item.iconName;
    }

    return normalizedItem;
}

function validateProviderContract(widgetHelper, logger) {
    var requiredMethods = [
        "canCreate",
        "canFilter",
        "canSavePreferences",
        "canConfigureColumns",
        "getAllAvailableColumns",
        "getAppliedFiltersInfoMessage",
        "getChoiceValues",
        "getDefaultColumns",
        "getDetailViewPage",
        "getFilterFields",
        "getIdField",
        "getRowClickAction",
        "getCellContent",
        "getOrderBy",
        "getOrderDirection",
        "getPageTitle",
        "getTableColumns",
        "getTableData",
        "getTableLimit",
        "getTotalRecords",
        "saveUserPreference",
        "showAppliedFilters",
        "showTableMetadata",
    ];

    var missingMethods = requiredMethods.filter(function (methodName) {
        return typeof widgetHelper[methodName] !== "function";
    });

    if (missingMethods.length > 0) {
        logger.error({
            message: "Provider is missing required methods",
            missingMethods: missingMethods,
        });
        return false;
    }

    return true;
}

function resolveEffectiveFilters(filters) {
    return Array.isArray(filters) ? filters : [];
}

function normalizeColumns(columns) {
    if (!Array.isArray(columns)) {
        return [];
    }

    return columns.map(normalizeColumn).filter(Boolean);
}

function normalizeColumn(column) {
    if (!column || typeof column !== "object") {
        return null;
    }

    if (typeof column.name !== "string" || !column.name.trim()) {
        return null;
    }

    var normalized = {
        name: column.name,
        label: typeof column.label === "string" ? column.label : "",
    };

    if (typeof column.width === "string" && column.width) {
        normalized.width = column.width;
    }

    if (typeof column.minWidth === "string" && column.minWidth) {
        normalized.minWidth = column.minWidth;
    }

    if (typeof column.maxWidth === "string" && column.maxWidth) {
        normalized.maxWidth = column.maxWidth;
    }

    if (typeof column.sourceField === "string" && column.sourceField) {
        normalized.sourceField = column.sourceField;
    }

    if (typeof column.useDisplayValue === "boolean") {
        normalized.useDisplayValue = column.useDisplayValue;
    }

    return normalized;
}

function buildUnifiedFilterFields(allColumns, configuredFilterFields) {
    var configuredMap = {};
    var configured = normalizeFilterFields(configuredFilterFields);

    for (var i = 0; i < configured.length; i++) {
        configuredMap[configured[i].field] = configured[i];
    }

    var unified = [];
    var normalizedAllColumns = normalizeColumns(allColumns);

    for (var j = 0; j < normalizedAllColumns.length; j++) {
        var column = normalizedAllColumns[j];
        if (!column || !column.name) {
            continue;
        }

        if (configuredMap[column.name]) {
            unified.push(configuredMap[column.name]);
            continue;
        }

        unified.push({
            field: column.name,
            label: column.label || column.name,
            type: "string",
        });
    }

    // Keep explicitly configured filter fields that are not present in columns.
    for (var k = 0; k < configured.length; k++) {
        var configuredField = configured[k];
        var existsInUnified = unified.some(function (item) {
            return item.field === configuredField.field;
        });

        if (!existsInUnified) {
            unified.push(configuredField);
        }
    }

    return unified;
}

function normalizeFilterFields(filterFields) {
    if (!Array.isArray(filterFields)) {
        return [];
    }

    return filterFields
        .map(normalizeFilterField)
        .filter(Boolean);
}

function normalizeFilterField(filterField) {
    if (!filterField || typeof filterField !== "object") {
        return null;
    }

    var fieldName =
        typeof filterField.field === "string" ? filterField.field.trim() : "";

    if (!fieldName) {
        return null;
    }

    var normalized = Object.assign({}, filterField);
    normalized.field = fieldName;
    normalized.label =
        typeof filterField.label === "string" && filterField.label
            ? filterField.label
            : fieldName;
    normalized.type =
        typeof filterField.type === "string" && filterField.type
            ? filterField.type
            : "string";

    return normalized;
}

function getReferenceDisplayValue(tableName, sysId) {
    if (!tableName || !sysId) {
        return "";
    }

    try {
        var gr = new GlideRecord(tableName);
        if (gr.get(sysId)) {
            return gr.getDisplayValue() || "";
        }
    } catch (error) {
        // Return empty string on lookup failures to keep client flow resilient.
    }

    return "";
}

function sanitizeHref(rawHref) {
    if (!rawHref) {
        return "";
    }

    var href = String(rawHref).trim();
    if (!href) {
        return "";
    }

    if (/^(javascript:|data:|vbscript:)/i.test(href)) {
        return "";
    }

    if (
        href.indexOf("?") === 0 ||
        href.indexOf("/") === 0 ||
        href.indexOf("#") === 0
    ) {
        return href;
    }

    if (/^(https?:|mailto:|tel:)/i.test(href)) {
        return href;
    }

    if (!/^[a-zA-Z][a-zA-Z\d+.-]*:/.test(href)) {
        return href;
    }

    return "";
}

function sanitizeTarget(rawTarget) {
    var target = String(rawTarget || "_self").trim();
    var allowedTargets = {
        _self: true,
        _blank: true,
        _parent: true,
        _top: true,
    };

    return allowedTargets[target] ? target : "_self";
}
